import React from "react";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Layout({ children }) {
  return (
    <>
      <Navbar />
      {/* Banner tagline */}
      <div style={{
        background: "linear-gradient(90deg, #004080, #0066cc, #3399ff)",
        color: "white",
        textAlign: "center",
        padding: "12px",
        fontStyle: "italic",
        fontWeight: "bold",
        letterSpacing: "1px",
        boxShadow: "0 2px 6px rgba(0,0,0,0.2)"
      }}>
        ✨ Motif‑driven healing for communities ✨
      </div>
      <main>{children}</main>
      <Footer />
    </>
  );
}

export default Layout;
